const d = $input.first().json.body || $input.first().json;

const PRODUCT_META = {
  'leadcore': {
    name:     'LeadCore™',
    tagline:  'AI Lead Qualification & CRM Enrichment',
    file:     'P03-LeadCore.json',
    docs:     'https://curcible.com/docs/leadcore',
    setup:    '1–2 hours',
    price:    '$79'
  },
  'inboxcore': {
    name:     'InboxCore™',
    tagline:  'AI Email Triage & Auto-Reply',
    file:     'P01-InboxCore.json',
    docs:     'https://curcible.com/docs/inboxcore',
    setup:    '1–2 hours',
    price:    '$79'
  },
  'contentcore': {
    name:     'ContentCore™',
    tagline:  'Auto SEO Blog Writer',
    file:     'P02-ContentCore.json',
    docs:     'https://curcible.com/docs/contentcore',
    setup:    '2–3 hours',
    price:    '$79'
  },
  'postcore': {
    name:     'PostCore™',
    tagline:  'Social Media Auto-Publisher',
    file:     'P04-PostCore.json',
    docs:     'https://curcible.com/docs/postcore',
    setup:    '3–5 hours',
    price:    '$79'
  },
  'reportcore': {
    name:     'ReportCore™',
    tagline:  'Weekly Analytics Digest',
    file:     'P05-ReportCore.json',
    docs:     'https://curcible.com/docs/reportcore',
    setup:    '2–4 hours',
    price:    '$79'
  },
  'knowcore': {
    name:     'KnowCore™',
    tagline:  'WhatsApp AI Chatbot + RAG',
    file:     'P06-KnowCore.json',
    docs:     'https://curcible.com/docs/knowcore',
    setup:    '4–6 hours',
    price:    '$99'
  },
  'meetcore': {
    name:     'MeetCore™',
    tagline:  'AI Meeting Summary & Follow-Up',
    file:     'P07-MeetCore.json',
    docs:     'https://curcible.com/docs/meetcore',
    setup:    '2–4 hours',
    price:    '$79'
  },
  'schedcore': {
    name:     'SchedCore™',
    tagline:  'AI Scheduling & Booking Automation',
    file:     'P08-SchedCore.json',
    docs:     'https://curcible.com/docs/schedcore',
    setup:    '2–3 hours',
    price:    '$79'
  }
};

const permalink = (d.permalink || '').toLowerCase().trim();
const meta = PRODUCT_META[permalink];

if (!meta) {
  throw new Error(`Unknown product permalink: "${permalink}"`);
}

// Download URL: Gumroad serves the file if you upload it as a product attachment.
// Alternatively, host the .json files at a stable URL (e.g. Cloudflare R2 or Netlify /public)
// and set the DOWNLOAD_BASE_URL env var (e.g. https://curcible.com/downloads)
const downloadBase = $env.DOWNLOAD_BASE_URL || 'https://curcible.com/downloads';

return [{
  json: {
    // Purchase data
    sale_id:      d.sale_id,
    email:        d.email,
    full_name:    d.full_name || '',
    first_name:   (d.full_name || '').split(' ')[0] || 'there',
    permalink,
    license_key:  d.license_key,
    price_cents:  d.price_cents,
    ip_country:   d.ip_country,
    purchased_at: d.purchased_at || new Date().toISOString(),
    is_test:      d.test === true,

    // Product metadata
    product_name:    meta.name,
    product_tagline: meta.tagline,
    product_file:    meta.file,
    product_docs:    meta.docs,
    setup_time:      meta.setup,
    download_url:    `${downloadBase}/${meta.file}`
  }
}];
